"use client"

import styles from "./page.module.css";
import { useEffect, useRef, useState } from "react";
import { useGSAP } from "@gsap/react";
import gsap from 'gsap';
import Coordinates from "@/component/Coordinates/Coordinates";
import Corner from "@/component/Corner/Corner";

export default function Home() {
  gsap.registerPlugin(useGSAP);
  const test = useRef<HTMLDivElement>(null!);


  let anim: gsap.core.Tween;

  useGSAP(() => {
    console.log('test')
    anim = gsap.to('#test', { rotation: "+=360", duration: 1, ease: "none"}).repeat(Infinity).pause();
    console.log(anim)
  })



  function spin() {

    if (anim.isActive()) {
      anim.pause()
    } else {
      anim.play();
    }
    
  }





  return (
    <div className={styles.page}>
      <main className={styles.main}>
        <div
        onClick={spin}
        ref={test}
        id="test" className={styles.test}>
        </div>


        <Coordinates/>
        
        <Corner/>

      </main>
    </div>
  );
}
